 LAYER
    NAME "OGF_preCarto_seuil70"
    TYPE RASTER
    STATUS ON

    DATA "file:///media/Data10/Forestimator/Autre/THRESH_MIX_q70_v3_DLG.tif"
    PROJECTION
        "init=epsg:31370"
    END

    PROCESSING "BANDS=1"
    CLASSITEM "[pixel]"

    CLASS
        EXPRESSION "1"
        STYLE
            COLOR 0 0 0
        END
    END

    CLASS
        EXPRESSION "2"
        STYLE
            OPACITY 0
        END
    END

    OFFSITE 0 0 0

    METADATA
        "wms_title" "Pre carto Old Growth Forest avec seuil de 70"
        "wms_srs"   "EPSG:31370"
    END
END


